      "reason": "Cryptographic verification of Data Streams reports is delegated to external verifier contract (out of scope)"
    }
  },
  "trust_assumptions": {
    "admin_roles": {
      "trust_level": "TRUSTED",
      "description": "DEFAULT_ADMIN_ROLE and role managers",
