      "impact": "Conditional loss of funds, DoS of core functionality, or broken invariants",
      "examples": [
        "Auction participation blocking (DoS)",
        "Slippage threshold bypass under specific conditions",
        "Stale price data enabling unfavorable trades"
      ]
    },
    "Low": {
      "impact": "Minor issues, informational, or gas optimizations",
      "examples": [
        "Event emission issues",
        "Non-critical rounding imprecision",
        "Gas inefficiencies"
      ]
    },
    "Informational": {
      "impact": "Best practice recommendations",
      "examples": [
        "Code style improvements",
        "Documentation gaps"
      ]
    }
  },
  "publicly_known_issues": [
